DROP TABLE IF EXISTS issue4633_right; DROP TABLE IF EXISTS issue4633_left;
CREATE TABLE issue4633_left (id bigint, owner_id uint, ref_id uint, created_at uint, active uint); CREATE TABLE issue4633_right ( id bigint, name text indexed stored, descr text indexed stored, color_name string indexed attribute, brand_name string indexed attribute, cat_name string indexed attribute, gender_code string indexed attribute, flag uint, brand_id uint, color_id uint, categories mva, product_id uint, is_lost uint, price float, discount uint, suggest mva );
