INSERT INTO issue4633_right(id, name, descr, color_name, brand_name, cat_name, gender_code, flag, brand_id, color_id, categories, product_id, is_lost, price, discount, suggest) VALUES (101, 'n1', 'd1', 'red', 'b1', 'c1', 'm', 0, 11, 21, (1,2), 1001, 0, 4700, 0, (10,20)), (102, 'n2', 'd2', 'blue', 'b2', 'c2', 'f', 0, 12, 22, (2,3), 1002, 0, 4900, 0, (20,30)), (103, 'n3', 'd3', 'green','b1', 'c3', 'm', 0, 11, 23, (1,3), 1003, 0, 7000, 0, (30,40));
SELECT id FROM issue4633_left LEFT JOIN issue4633_right ON issue4633_left.ref_id = issue4633_right.id WHERE active = 1 AND owner_id = 12345 AND issue4633_right.price >= 4500 AND issue4633_right.price <= 5000 ORDER BY id ASC OPTION max_matches = 1000 FACET issue4633_right.gender_code ORDER BY COUNT(*) DESC LIMIT 1000 FACET issue4633_right.categories ORDER BY COUNT(*) DESC LIMIT 1000 FACET issue4633_right.brand_id ORDER BY COUNT(*) DESC LIMIT 1000 FACET issue4633_right.color_id ORDER BY COUNT(*) DESC LIMIT 1000 FACET issue4633_right.suggest ORDER BY COUNT(*) DESC LIMIT 1000;;
